INSERT INTO `mob` VALUES (100100,'Snail','달팽이',1,_binary '3',0,0,'메소, 활전용 화살, 석궁전용 화살, 청동의 원석, 가넷의 원석, 연두색 머리띠, 빨간 포션, 망토 방어력 주문서 60%, 투구 방어력 주문서 10%, 달팽이의 껍질, 초록사과, 전신 갑옷 민첩 주문서 60%','https://static.wikia.nocookie.net/maplestory/images/6/6c/Mob_Snail.png'),(100101,'Blue Snail','파란 달팽이',2,_binary '4',15,15,'메소, 자수정의 원석, 활전용 화살, 석궁전용 화살, 파란색 원라인 티셔츠, 파란 달팽이의 껍질, 회갈색 수련복 바지, 회갈색 수련복, 회색 고무줄 바지, 몬스터 카드, 빨간 포션, 빨간 줄무늬 티셔츠, 망토 체력 주문서 100%, 강철의 원석, 초록사과','https://static.wikia.nocookie.net/maplestory/images/0/0b/Mob_Blue_Snail.png'),(120100,'Shroom','스포아',2,_binary '5',15,15,'메소, 아쿠아마린의 원석, 활전용 화살, 석궁전용 화살, 파란 칠부바지, 필드 대거, 그린 아벨린 치마, 아이스 진, 미스릴의 원석, 버섯의 포자, 빨간 포션, 망토 체력 주문서 60%, 초록사과','logo.png'),(130100,'Stump','스텀프',4,_binary '8',30,30,'메소, 아다만티움의 원석, 활전용 화살, 석궁전용 화살, 브라운 미들 래더, 합금 활, 에메랄드의 원석, 주노, 바둑판, 빨간 포션, 망토 체력 주문서 10%, 상의 방어력 주문서 10%, 나뭇가지, 삼각 자마다르, 초록사과, 레전드 바지, 피스톨','https://static.wikia.nocookie.net/maplestory/images/2/27/Mob_Stump.png'),(130101,'Red Snail','빨간 달팽이',4,_binary '8',30,30,'메소, 자수정 귀고리, 활전용 화살, 석궁전용 화살, 브라운 듀오, 브라운 우드탑, 가죽 핸드백, 메탈 완드, 오팔의 원석, 홍몽 바지, 빨간 포션, 빨간 달팽이의 껍질, 망토 마나 주문서 100%, 전신 갑옷 민첩 주문서 10%, 은의 원석, 목검, 홍몽 바지, 초록사과','https://static.wikia.nocookie.net/maplestory/images/9/9e/Mob_Red_Snail.png'),(3230100,'Curse Eye','',0,_binary '0',0,0,'','https://static.wikia.nocookie.net/maplestory/images/a/a3/Mob_Curse_Eye.png'),(4220001,'Seruf','세르프',45,_binary '0',150,150,'업데이트예정','https://static.wikia.nocookie.net/maplestory/images/d/d6/Mobicon_Seruf.png'),(5100001,'Transforming Jr. Yeti','주니어 예티',50,_binary '0',20,20,'업데이트예정','https://static.wikia.nocookie.net/maplestory/images/f/fc/Mob_Jr._Yeti.png'),(5130106,'Transforming Dark Jr. Yeti','다크 주니어 예티',56,_binary '0',40,40,'업데이트예정','https://static.wikia.nocookie.net/maplestory/images/9/9b/Mob_Dark_Jr._Yeti.png'),(5220001,'King Clang','킹크랑',55,_binary '0',100,100,'업데이트예정','https://static.wikia.nocookie.net/maplestory/images/2/21/Mobicon_King_Clang.png'),(6130201,'Blin','깨비',60,_binary '0',100,100,'업데이트예정'